Method.Source:
/// <summary>
/// Gets or sets the value of the datacontract parameter RecID.
/// </summary>
/// <param name = "_recId">RecId</param>
/// <returns>list of record ids</returns>
[
    DataMemberAttribute(identifierStr(RecId)), 
    AifCollectionTypeAttribute('_recId', Types::Int64, extendedTypeStr(RecId)),
    SysOperationControlVisibilityAttribute(False)
]
public List parmRecId(List _recId = recId)
{
    recId = _recId;
    return recId;
}
